import{_ as r,o as t,c as n,j as e,a as s,a1 as o}from"./chunks/framework.Bp7r_-XI.js";const f=JSON.parse('{"title":"恋人的契约","description":"","frontmatter":{},"headers":[],"relativePath":"4.资源分区/7.物品与装备/4.奇物/3.B级/恋人的契约.md","filePath":"4.资源分区/7.物品与装备/4.奇物/3.B级/恋人的契约.md"}'),d={name:"4.资源分区/7.物品与装备/4.奇物/3.B级/恋人的契约.md"};function _(l,a,p,i,c,h){return t(),n("div",null,[...a[0]||(a[0]=[e("h1",{id:"恋人的契约",tabindex:"-1"},[s("恋人的契约 "),e("a",{class:"header-anchor",href:"#恋人的契约","aria-label":'Permalink to "恋人的契约"'},"​")],-1),e("table",{class:"bannerparthead"},[e("tbody",null,[e("tr",{id:"hdr"},[e("td",{class:"runninghead",nowrap:""},"TMD：新世短歌037")])])],-1),o('<h1 id="恋人的契约-1" tabindex="-1">恋人的契约 <a class="header-anchor" href="#恋人的契约-1" aria-label="Permalink to &quot;恋人的契约&quot;">​</a></h1><p>恋人的契约<br> 价格：B+4000<br> 分类：奇物<br> 位置：饰品<br> 描述：能够通过接吻来注入，从而操纵他人的特殊类型装备，通俗意义上来讲就是外观和虫子一样的活体装备，平时隐藏在装备者的口中，在使用时能被看到爬行在舌头上的多节长条形虫类，也有着“和好的吻”等称呼。<br> 虽然性质非常恶劣，但正如其名，这一装备是源自于祝福而诞生的产物。<br> 效果：通常而言，这一装备不能正常在战斗中使用，只能在目标自愿与你接吻时（如果目标处于无助，或者无法反抗你的行为时也可以强行进行接吻），你才能以【风度+表达：演技+辅助专业：心理学（学识）】对抗目标的意志豁免，若对抗成功则目标不会发觉你在向其注入【恋人契约】，这是一个B级祝福来源的【思维控制】效果。</p><p>然而，你也可以在使用符合上述（接吻）画风肉搏类攻击也能注入恋人契约，或是在擒抱状态下使用这一装备，这意味着你可以在被擒抱下主动进行攻击，正常使用你自己的攻击检定（如同你具有免疫擒抱状态一样处理），但伤害类型转为精神伤害；一旦符合画风的肉搏类攻击或是你在擒抱状态下的攻击命中，你就可以向其注入【恋人契约】，这一擒抱即使目标具有免疫擒抱能力也视为满足注入恋人契约的条件，只需要你的擒抱攻击命中即可。倘若目标已被你击败，则你无需擒抱也能向其注入恋人契约；你只需要消费2点意志力，即可在该场景内使注入恋人契约的攻击可以自由留手。</p><p>注入恋人契约时，目标需要使用强韧豁免对抗你的攻击伤害出目，失败则承受差值的魅惑异常不良点数；若是以非战斗的形式注入，则目标承受对抗差值的魅惑不良点数（这种方式不会造成伤害，但会消耗你的2点意志力，每场景只需要因此消耗一次即可），但这种方法无法使其进入魅惑不良点数的毁灭性后果，并且一旦你导致其生命陷入危险，或者使其受到极大冲击（例如让没有杀过人的人去杀人，或者要求他去屠杀），恋人契约的效果便会自动解除。恋人契约始终视为B级祝福来源的效果。<br> 无论如何，注入恋人契约的行为始终会使目标承受1点不可豁免的魅惑不良点数影响，但可以被承受异常点数减少的能力正常降低，也可以正常被异常点数恢复的能力移除。</p><hr><p>Copyright ? 2025 <a href="http://www.goddessfantasy.net/bbs/index.php?board=2008.0" target="_blank" rel="noreferrer">TMDtrpg制作组</a>. All Rights Reserved.</p>',6)])])}const m=r(d,[["render",_]]);export{f as __pageData,m as default};
